    $role = $obj.payload.role
    $parts = @()
    foreach ($c in $obj.payload.content) {
      if ($null -ne $c.text -and $c.text -ne '') { $parts += $c.text }
    }
    $text = $parts -join "`n"
    if ($text -match '视频|PPT|AI|不擅长|目标|目的|宣传') {
      Write-Output ("LINE " + $i + " ROLE=" + $role)
      Write-Output $text
      Write-Output '----'
    }
  }
